<?php
 class FolderController extends PageController { private string $usersDir; public function __construct() { parent::__construct(); $this->usersDir = DATA_DIR . '/users'; if (!is_dir($this->usersDir)) { mkdir($this->usersDir, 0755, true); } } public function action_create(): void { $message = ''; $error = ''; if ($this->request->isPost()) { $login = trim($this->request->post('login', '')); $password = trim($this->request->post('password', '')); if ($login === '' || $password === '') { $error = 'Ідентифікатор та пароль є обов\'язковими.'; } elseif (!preg_match('/^[a-zA-Z0-9_]{1,64}$/', $login)) { $error = 'Ідентифікатор: 1-64 символи (латинські літери, цифри, _).'; } else { $userDir = $this->usersDir . '/' . $login; if (is_dir($userDir)) { $error = "Відсік для пілота \"{$login}\" вже існує!"; } else { mkdir($userDir, 0755, true); $subfolders = ['video', 'music', 'photo']; foreach ($subfolders as $sub) { $subPath = $userDir . '/' . $sub; mkdir($subPath, 0755, true); file_put_contents($subPath . '/readme.txt', "Відсік [{$sub}] пілота [{$login}]\nСтворено: " . date('Y-m-d H:i')); file_put_contents($subPath . '/log_1.txt', "Запис 1 системи {$sub} — OK"); file_put_contents($subPath . '/log_2.txt', "Запис 2 системи {$sub} — OK"); } file_put_contents($userDir . '/.password', password_hash($password, PASSWORD_DEFAULT)); $message = "Відсік даних \"{$login}\" успішно створено з підпапками: video, music, photo!"; } } } $folders = $this->getUserFolders(); $this->render('folder/create', [ 'message' => $message, 'error' => $error, 'folders' => $folders, ], 'Відсіки даних — Створення'); } public function action_delete(): void { $message = ''; $error = ''; if ($this->request->isPost()) { $login = trim($this->request->post('login', '')); $password = trim($this->request->post('password', '')); if ($login === '' || $password === '') { $error = 'Ідентифікатор та пароль є обов\'язковими.'; } elseif (!preg_match('/^[a-zA-Z0-9_]{1,64}$/', $login)) { $error = 'Ідентифікатор: 1-64 символи (латинські літери, цифри, _).'; } else { $userDir = $this->usersDir . '/' . $login; if (!is_dir($userDir)) { $error = "Відсік \"{$login}\" не знайдено."; } else { $hashFile = $userDir . '/.password'; if (!file_exists($hashFile)) { $error = 'Файл автентифікації не знайдено.'; } elseif (!password_verify($password, file_get_contents($hashFile))) { $error = 'Невірний пароль. Доступ заборонено.'; } else { $this->deleteDirectory($userDir); $message = "Відсік \"{$login}\" та весь вміст успішно знищено!"; } } } } $this->render('folder/delete', [ 'message' => $message, 'error' => $error, ], 'Відсіки даних — Видалення'); } private function getUserFolders(): array { $folders = []; $dirs = glob($this->usersDir . '/*', GLOB_ONLYDIR); if ($dirs) { foreach ($dirs as $dir) { $name = basename($dir); $subfolders = []; $subDirs = glob($dir . '/*', GLOB_ONLYDIR); if ($subDirs) { foreach ($subDirs as $subDir) { $subName = basename($subDir); $fileCount = count(glob($subDir . '/*')); $subfolders[] = ['name' => $subName, 'files' => $fileCount]; } } $folders[] = ['name' => $name, 'subfolders' => $subfolders]; } } return $folders; } private function deleteDirectory(string $dir): void { $items = new RecursiveIteratorIterator( new RecursiveDirectoryIterator($dir, RecursiveDirectoryIterator::SKIP_DOTS), RecursiveIteratorIterator::CHILD_FIRST ); foreach ($items as $item) { if ($item->isDir()) { rmdir($item->getPathname()); } else { unlink($item->getPathname()); } } rmdir($dir); } } 